    wertzfdlz            number(*, 12),
    wertzfkapitalbindung number(*, 5),
    wertzfverspaetung    number(*, 5),
    wertzfstillstand     number(*, 5),
    wertzfgesamt         number(*, 5),
    wertgesamt           number(*, 5),
    erstelltam           date
);


